export type MessageCatalog = Record<MessageKey, MessageEntry>

export const DEFAULT_LOCALE: 'en'
export const PSEUDO_LOCALE: 'en-XA'
export const LONG_LOCALE: 'en-XL'
export const SYSTEM_LOCALE_CHOICE: 'system'
export const SUPPORTED_UI_LOCALES: readonly ['en', 'es']
export const SPECIAL_TEST_LOCALES: readonly ['en-XA', 'en-XL']
export const LOCALE_CHOICES: readonly LocaleChoice[]
export const GROCERY_LOCALES: readonly GroceryLocale[]
export const MESSAGE_KEYS: readonly MessageKey[]
export const LOCALE_LABEL_KEYS: Record<LocaleChoice, MessageKey>
export const catalogByLocale: Record<'en' | 'es', MessageCatalog>

export type I18n = {
    locale: UiLocale
    localeChoice: LocaleChoice
    systemLocale: string
    groceryLocale: GroceryLocale
    catalog: MessageCatalog
    t: (key: MessageKey, values?: MessageValues) => string
    number: (value: number, options?: Intl.NumberFormatOptions) => string
    date: (value: Date | number | string, options?: Intl.DateTimeFormatOptions) => string
    plural: (count: number, forms: PluralMessage) => string
}

export function isLocaleChoice(value: unknown): value is LocaleChoice
export function normalizeLocale(value: unknown): string
export function getLocaleLanguage(locale: string): string
export function matchSupportedLocale(locale: string): UiLocale
export function resolveLocale(localeChoice?: string, systemLocale?: string): UiLocale
export function resolveGroceryLocale(localeChoice?: string, systemLocale?: string): GroceryLocale
export function getCatalog(locale: string): MessageCatalog
export function createI18n(options?: { locale?: string; localeChoice?: string; systemLocale?: string }): I18n
export function translate(catalog: Partial<MessageCatalog>, key: MessageKey, values?: MessageValues, locale?: string): string
export function selectPluralMessage(message: MessageEntry, count?: number, locale?: string): string
export function selectPluralForm(forms: PluralMessage, count: number, locale?: string): string
export function interpolate(message: string, values?: MessageValues): string
export function formatNumber(value: number, locale?: string, options?: Intl.NumberFormatOptions): string
export function formatDate(value: Date | number | string, locale?: string, options?: Intl.DateTimeFormatOptions): string
export function pseudoLocalizeText(value: string, options?: { expansion?: number }): string
export function createPseudoCatalog(source?: MessageCatalog): MessageCatalog
export function createLongStringCatalog(source?: MessageCatalog): MessageCatalog
export function assertCompleteCatalog(locale: string, catalog: Partial<MessageCatalog>, source?: MessageCatalog): void
